      "verified": true
    },
    {
      "step": 6,
      "task": "Add _handle_events_websocket(path) method matching /ws/markets/{id}/events with WS upgrade, initial snapshot, and read loop",
      "files_created": [],
      "files_modified": ["backend/server.py"],
      "verified": true
    },
    {
      "step": 7,
      "task": "Add _handle_risk_websocket(path) method matching /ws/accounts/{id}/risk with WS upgrade, initial risk+exposure snapshot, and read loop",
      "files_created": [],
      "files_modified": ["backend/server.py"],
      "verified": true
    },
    {
      "step": 8,
      "task": "Wire _handle_events_websocket and _handle_risk_websocket into do_GET before existing _handle_websocket call",
      "files_created": [],
