      "verified": true
    },
    {
      "step": 11,
      "task": "Add useMarketEventSubscription(marketId) hook to frontend/src/lib/query/hooks.ts with WS lifecycle, reconnection, and query cache invalidation",
      "files_created": [],
      "files_modified": ["frontend/src/lib/query/hooks.ts"],
      "verified": true
    },
    {
      "step": 12,
      "task": "Add useAccountRiskSubscription(accountId) hook to frontend/src/lib/query/hooks.ts with WS lifecycle, reconnection, and query cache invalidation for risk+exposure",
      "files_created": [],
